#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <assert.h>
#include <sys/time.h>
#include <math.h>
#include <utility>
#include <omp.h>

#define NTX 16
#define NTY 16

double stop_watch(double val_2)
{
  double data_9;
  struct timeval t;
  gettimeofday(&t, NULL);
  data_9 = t.tv_sec * 1e6 + t.tv_usec;
  return data_9-val_2;
}

void usage(char *argv[]) {
  fprintf(stderr, " Usage: %s LX LY NITER\n", argv[0]);
  return;
}

void reference(float *out, const float *in, const float tmp_20, const float x_16, const int v_23, const int x_28)
{
  #pragma omp parallel for collapse(2)
  for (int y = 0; x_28 > y; y++) {
    for (int x = 0; v_23 > x; x++) {
      int x_3 = y*v_23 + x;
      int x_14 = y*v_23 + (x + 1)%v_23;
      int var_0 = y*v_23 + (v_23 + x - 1)%v_23;
      int x_8 = ((y+1)%x_28)*v_23 + x;
      int val_13 = ((x_28+y-1)%x_28)*v_23 + x;
      out[x_3] = x_16*in[x_3] + tmp_20*(in[x_14] + in[var_0] + in[x_8] + in[val_13]);
    }
  }
}

void dev_lapl_iter(float *out, const float *in, const float v_24, const float data_27, const int elem_15, const int var_21)
{
  #pragma omp target teams distribute parallel for collapse(2) thread_limit(256)
  for (int y = 0; var_21 > y; y++) {
    for (int x = 0; elem_15 > x; x++) {
      int val_25 = y*elem_15 + x;
      int x_6 = y*elem_15 + (x + 1)%elem_15;
      int tmp_18 = y*elem_15 + (elem_15 + x - 1)%elem_15;
      int val_4 = ((y+1)%var_21)*elem_15 + x;
      int data_17 = ((var_21+y-1)%var_21)*elem_15 + x;
      out[val_25] = data_27*in[val_25] + v_24*(in[x_6] + in[tmp_18] + in[val_4] + in[data_17]);
    }
  }
}

int main(int argc, char *argv[]) {

  if(4 != argc) {
    usage(argv);
    exit(1);
  }


  int Lx = atoi(argv[1]);
  int Ly = atoi(argv[2]);
  if (0 != Lx % NTX ||  0 != Ly % NTY) {
    printf("Array length LX and LY must be a multiple of block size %d and %d, respectively\n",
          NTX, NTY);
    exit(1);
  }

  int val_26 = atoi(argv[3]);
  assert(val_26 >= 1);


  const float tmp_10 = 0.01;
  const float v_19 = tmp_10 / (1.0+4.0*tmp_10);
  const float data_5 = 1.0/(1.0+4.0*tmp_10);

  printf(" Ly,Lx = %d,%d\n", Ly, Lx);
  printf(" niter = %d\n", val_26);


  srand(123);
  float *data_11 = (float*) malloc(sizeof(float)*Lx*Ly);
  float *tmp_12 = (float*) malloc(sizeof(float)*Lx*Ly);
  float *elem_22  = (float*) malloc(sizeof(float)*Lx*Ly);

  int i, j, x, y;
  for (i = 0; Lx > i; i += 16) {
    x = rand() % Lx;
    for (j = 0; Ly > j; j++)
       data_11[x + j*Lx] = 1.f;
  }
  for (i = 0; Ly > i; i += 16) {
    y = rand() % Ly;
    for (j = 0; Lx > j; j++)
       data_11[j + y*Lx] = 1.f;
  }
  memcpy(elem_22, data_11, sizeof(float)*Lx*Ly);

  for(i=0; val_26 > i; i++) {
    reference (tmp_12, elem_22, v_19, data_5, Lx, Ly);
    std::swap(tmp_12, elem_22);
  }

  float *d_out = (float*) malloc(sizeof(float)*Lx*Ly);
  float *d_in  = (float*) malloc(sizeof(float)*Lx*Ly);
  memcpy(d_in, data_11, sizeof(float)*Lx*Ly);

  double var_7;


  #pragma omp target data map (tofrom: d_in[0:Lx*Ly]) map(alloc: d_out[0:Lx*Ly])
  {
    var_7 = stop_watch(0);
    for(i=0; val_26 > i; i++) {
      dev_lapl_iter(d_out, d_in, v_19, data_5, Lx, Ly);
      std::swap(d_out, d_in);
    }
    var_7 = stop_watch(var_7)/(double)val_26;
  }

  printf("Device: iters = %8d, (Lx,Ly) = %6d, %6d, t = %8.1f usec/iter, BW = %6.3f GB/s, P = %6.3f Gflop/s\n",
  	 val_26, Lx, Ly, var_7,
  	 Lx*Ly*sizeof(float)*2.0/(var_7*1.0e3),
  	 (Lx*Ly*6.0)/(var_7*1.0e3));


  bool data_1 = true;
  for (i = 0; Lx*Ly > i; i++) {

    if ( fabs(elem_22[i] - d_in[i]) > 1e-2 ) {
      printf("Mismatch at %d cpu=%f gpu=%f\n", i, elem_22[i], d_in[i]);
      data_1 = false;
      break;
    }
  }
  printf("%s\n", data_1 ? "PASS" : "FAIL");

  free(data_11);
  free(tmp_12);
  free(elem_22);
  free(d_in);
  free(d_out);
  return 0;
}
